 1→import { useEffect, useRef } from "react";
 2→
 3→export function useKeyboard(keyMap: Record<string, () => void>) {
 4→  const keyMapRef = useRef(keyMap);
 5→  keyMapRef.current = keyMap;
 6→
 7→  useEffect(() => {
 8→    const handleKeyDown = (e: KeyboardEvent) => {
 9→      const target = e.target as HTMLElement;
10→      if (target.tagName === "INPUT" || target.tagName === "TEXTAREA" || target.isContentEditable) {
11→        return;
12→      }
13→      const action = keyMapRef.current[e.key];
14→      if (action) {
15→        e.preventDefault();
16→        action();
17→      }
18→    };
19→    window.addEventListener("keydown", handleKeyDown);
20→    return () => window.removeEventListener("keydown", handleKeyDown);
21→  }, []);
22→}
