  1→import { useState, useRef, useEffect, useMemo, useCallback } from "react";
  2→import type { DebugEntry } from "../types";
  3→import { useToggleSet } from "../hooks/useToggleSet";
  4→import { useScrollToSelected } from "../hooks/useScrollToSelected";
  5→import { useRegisterViewActions, type ViewActionsRef } from "../hooks/useViewActions";
  6→
  7→type DebugLevel = "all" | "warn" | "error";
  8→
  9→interface DebugViewerProps {
 10→  entries: DebugEntry[];
 11→  viewActionsRef: ViewActionsRef;
 12→}
 13→
 14→export function DebugViewer({ entries, viewActionsRef }: DebugViewerProps) {
 15→  const [levelFilter, setLevelFilter] = useState<DebugLevel>("all");
 16→  const [searchText, setSearchText] = useState("");
 17→  const { set: expandedSet, toggle: toggleExpand, clear: clearExpanded, addAll } = useToggleSet();
 18→  const [selectedIndex, setSelectedIndex] = useState(0);
 19→  const bodyRef = useRef<HTMLDivElement>(null);
 20→  const selectedRef = useScrollToSelected(selectedIndex);
 21→
 22→  // Filter entries
 23→  const filtered = useMemo(() => {
 24→    let result = entries;
 25→
 26→    if (levelFilter === "warn") {
 27→      result = result.filter((e) => e.level === "warn" || e.level === "error");
 28→    } else if (levelFilter === "error") {
 29→      result = result.filter((e) => e.level === "error");
 30→    }
 31→
 32→    if (searchText) {
 33→      const lower = searchText.toLowerCase();
 34→      result = result.filter(
 35→        (e) =>
 36→          e.message.toLowerCase().includes(lower) ||
 37→          e.category.toLowerCase().includes(lower) ||
 38→          e.extra.toLowerCase().includes(lower),
 39→      );
 40→    }
 41→
 42→    return result;
 43→  }, [entries, levelFilter, searchText]);
 44→
 45→  // Clamp selected index
 46→  useEffect(() => {
 47→    if (selectedIndex >= filtered.length && filtered.length > 0) {
 48→      setSelectedIndex(filtered.length - 1);
 49→    }
 50→  }, [filtered.length, selectedIndex]);
 51→
 52→  const debugExpandAll = useCallback(() => {
 53→    const indices = filtered.map((_, i) => i).filter((i) => !!filtered[i].extra);
 54→    addAll(indices);
 55→  }, [filtered, addAll]);
 56→
 57→  useRegisterViewActions(viewActionsRef, { expandAll: debugExpandAll, collapseAll: clearExpanded });
 58→
 59→  return (
 60→    <div className="debug-viewer">
 61→      <div className="debug-viewer__header">
 62→        <span className="debug-viewer__title">Debug Log</span>
 63→
 64→        <div className="debug-viewer__filter-group">
 65→          <button
 66→            className={`debug-viewer__filter-btn${levelFilter === "all" ? " debug-viewer__filter-btn--active" : ""}`}
 67→            onClick={() => {
 68→              setLevelFilter("all");
 69→              clearExpanded();
 70→            }}
 71→          >
 72→            All
 73→          </button>
 74→          <button
 75→            className={`debug-viewer__filter-btn${levelFilter === "warn" ? " debug-viewer__filter-btn--active" : ""}`}
 76→            onClick={() => {
 77→              setLevelFilter("warn");
 78→              clearExpanded();
 79→            }}
 80→          >
 81→            Warn+
 82→          </button>
 83→          <button
 84→            className={`debug-viewer__filter-btn${levelFilter === "error" ? " debug-viewer__filter-btn--active" : ""}`}
 85→            onClick={() => {
 86→              setLevelFilter("error");
 87→              clearExpanded();
 88→            }}
 89→          >
 90→            Error
 91→          </button>
 92→        </div>
 93→
 94→        <input
 95→          className="debug-viewer__search"
 96→          type="text"
 97→          placeholder="Filter text..."
 98→          value={searchText}
 99→          onChange={(e) => {
100→            setSearchText(e.target.value);
101→            clearExpanded();
102→            setSelectedIndex(0);
103→          }}
104→          onKeyDown={(e) => {
105→            if (e.key === "Escape") {
106→              setSearchText("");
107→              clearExpanded();
108→            }
109→          }}
110→        />
111→
112→        <span className="debug-viewer__count">
113→          {filtered.length} / {entries.length}
114→        </span>
115→      </div>
116→
117→      <div className="debug-viewer__body" ref={bodyRef}>
118→        {filtered.length === 0 && <div className="picker__empty">No matching entries</div>}
119→
120→        {filtered.map((entry, idx) => {
121→          const isSelected = idx === selectedIndex;
122→          const isExpanded = expandedSet.has(idx);
123→          const hasExtra = !!entry.extra;
124→
125→          return (
126→            <div key={entry.line_num}>
127→              <div
128→                ref={isSelected ? selectedRef : null}
129→                className={`debug-entry${isSelected ? " debug-entry--selected" : ""}`}
130→                onClick={() => {
131→                  setSelectedIndex(idx);
132→                  if (hasExtra) toggleExpand(idx);
133→                }}
134→              >
135→                <span className="debug-entry__timestamp">{entry.timestamp}</span>
136→                <span className={`debug-entry__level debug-entry__level--${entry.level}`}>
137→                  {entry.level}
138→                </span>
139→                <span className="debug-entry__category">{entry.category}</span>
140→                <span className="debug-entry__message">{entry.message}</span>
141→                {entry.count > 1 && (
142→                  <span className="debug-entry__count">
143→                    {"\u00D7"}
144→                    {entry.count}
145→                  </span>
146→                )}
147→              </div>
148→              {isExpanded && hasExtra && <div className="debug-entry__extra">{entry.extra}</div>}
149→            </div>
150→          );
151→        })}
152→      </div>
153→    </div>
154→  );
155→}
