  1→import { useState, useEffect, useCallback } from "react";
  2→import { invoke } from "../lib/invoke";
  3→import { PopoutModal } from "./PopoutModal";
  4→
  5→interface SettingsResponse {
  6→  projects_dir: string | null;
  7→  default_dir: string;
  8→}
  9→
 10→interface SettingsModalProps {
 11→  onClose: () => void;
 12→  onSaved: () => void;
 13→}
 14→
 15→export function SettingsModal({ onClose, onSaved }: SettingsModalProps) {
 16→  const [projectsDir, setProjectsDir] = useState("");
 17→  const [defaultDir, setDefaultDir] = useState("");
 18→  const [error, setError] = useState("");
 19→  const [saving, setSaving] = useState(false);
 20→
 21→  useEffect(() => {
 22→    invoke<SettingsResponse>("get_settings")
 23→      .then((res) => {
 24→        setDefaultDir(res.default_dir);
 25→        setProjectsDir(res.projects_dir ?? res.default_dir);
 26→      })
 27→      .catch((err) => {
 28→        console.error("Failed to load settings:", err);
 29→      });
 30→  }, []);
 31→
 32→  const handleSave = useCallback(async () => {
 33→    setSaving(true);
 34→    setError("");
 35→    try {
 36→      await invoke<SettingsResponse>("set_projects_dir", { path: projectsDir.trim() || null });
 37→      onSaved();
 38→      onClose();
 39→    } catch (err) {
 40→      setError(String(err));
 41→    } finally {
 42→      setSaving(false);
 43→    }
 44→  }, [projectsDir, onSaved, onClose]);
 45→
 46→  const handleReset = useCallback(async () => {
 47→    setSaving(true);
 48→    setError("");
 49→    try {
 50→      const res = await invoke<SettingsResponse>("set_projects_dir", { path: null });
 51→      setProjectsDir(res.default_dir);
 52→      onSaved();
 53→      onClose();
 54→    } catch (err) {
 55→      setError(String(err));
 56→    } finally {
 57→      setSaving(false);
 58→    }
 59→  }, [onSaved, onClose]);
 60→
 61→  const handleKeyDown = useCallback(
 62→    (e: React.KeyboardEvent) => {
 63→      if (e.key === "Enter") {
 64→        e.preventDefault();
 65→        handleSave();
 66→      }
 67→    },
 68→    [handleSave],
 69→  );
 70→
 71→  return (
 72→    <PopoutModal
 73→      onClose={onClose}
 74→      header={<span className="settings-modal__title">Settings</span>}
 75→      initialWidth={520}
 76→      initialHeight={240}
 77→    >
 78→      <div className="settings-modal">
 79→        <label className="settings-modal__label" htmlFor="projects-dir">
 80→          Projects Directory
 81→        </label>
 82→        <input
 83→          id="projects-dir"
 84→          className="settings-modal__input"
 85→          type="text"
 86→          value={projectsDir}
 87→          onChange={(e) => {
 88→            setProjectsDir(e.target.value);
 89→            setError("");
 90→          }}
 91→          onKeyDown={handleKeyDown}
 92→          placeholder={defaultDir}
 93→          spellCheck={false}
 94→          autoFocus
 95→        />
 96→        <p className="settings-modal__hint">Default: {defaultDir}</p>
 97→        {error && <p className="settings-modal__error">{error}</p>}
 98→        <div className="settings-modal__actions">
 99→          <button
100→            className="settings-modal__btn settings-modal__btn--secondary"
101→            onClick={handleReset}
102→            disabled={saving}
103→          >
104→            Reset to Default
105→          </button>
106→          <button
107→            className="settings-modal__btn settings-modal__btn--primary"
108→            onClick={handleSave}
109→            disabled={saving}
110→          >
111→            Save
112→          </button>
113→        </div>
114→      </div>
115→    </PopoutModal>
116→  );
117→}
