  1→import { useState, useEffect, useCallback, useRef } from "react";
  2→import { invoke } from "./lib/invoke";
  3→import type { ViewState, SessionInfo } from "./types";
  4→import { useSession } from "./hooks/useSession";
  5→import { usePicker } from "./hooks/usePicker";
  6→import { useToggleSet } from "./hooks/useToggleSet";
  7→import { useKeyboard } from "./hooks/useKeyboard";
  8→import { useViewActionsRef, useViewActionCallbacks } from "./hooks/useViewActions";
  9→import { SessionPicker } from "./components/SessionPicker";
 10→import { MessageList } from "./components/MessageList";
 11→import { MessageDetail } from "./components/MessageDetail";
 12→import { TeamBoard } from "./components/TeamBoard";
 13→import { DebugViewer } from "./components/DebugViewer";
 14→import { InfoBar } from "./components/InfoBar";
 15→import { KeybindBar } from "./components/KeybindBar";
 16→import { ViewToolbar } from "./components/ViewToolbar";
 17→import { ProjectTree, useProjectKeys } from "./components/ProjectTree";
 18→import { ResizeHandle } from "./components/ResizeHandle";
 19→import { SettingsModal } from "./components/SettingsModal";
 20→
 21→export function App() {
 22→  const [view, setView] = useState<ViewState>("picker");
 23→  const [selectedMessage, setSelectedMessage] = useState(0);
 24→  const [pickerSelectedIndex, setPickerSelectedIndex] = useState(0);
 25→  const [showKeybinds, setShowKeybinds] = useState(true);
 26→  const [selectedProject, setSelectedProject] = useState<string | null>(null);
 27→  const [sidebarWidth, setSidebarWidth] = useState(180);
 28→  const [sidebarFocused, setSidebarFocused] = useState(false);
 29→  const [sidebarHighlight, setSidebarHighlight] = useState(0); // index in project list (0 = "All")
 30→  const [showSettings, setShowSettings] = useState(false);
 31→
 32→  const handleSelectProject = useCallback(
 33→    (project: string | null) => {
 34→      setSelectedProject(project);
 35→      setPickerSelectedIndex(0);
 36→      setSidebarFocused(false);
 37→      if (view !== "picker") setView("picker");
 38→    },
 39→    [view],
 40→  );
 41→
 42→  const session = useSession();
 43→  const picker = usePicker(selectedProject);
 44→  const projectKeys = useProjectKeys(picker.allSessions);
 45→
 46→  const { loadSession, loadDebugLog, sessionPath } = session;
 47→  const { discoverSessions, updateSessionOngoing } = picker;
 48→
 49→  const {
 50→    set: expandedMessages,
 51→    toggle: toggleMessage,
 52→    clear: clearExpanded,
 53→    addAll: expandMessages,
 54→  } = useToggleSet();
 55→
 56→  // Shared: fetch project dirs and discover sessions
 57→  const loadProjectDirs = useCallback(async () => {
 58→    try {
 59→      const dirs = await invoke<string[]>("get_project_dirs");
 60→      if (dirs.length > 0) {
 61→        discoverSessions(dirs);
 62→      }
 63→    } catch (err) {
 64→      console.error("Failed to get project dirs:", err);
 65→    }
 66→  }, [discoverSessions]);
 67→
 68→  // Auto-discover sessions on mount; show settings if no path configured
 69→  const discoveredRef = useRef(false);
 70→  useEffect(() => {
 71→    if (discoveredRef.current) return;
 72→    discoveredRef.current = true;
 73→    const discover = async () => {
 74→      let hasConfig = false;
 75→      try {
 76→        const settings = await invoke<{ projects_dir: string | null }>("get_settings");
 77→        hasConfig = settings.projects_dir != null;
 78→      } catch {
 79→        // no settings file yet
 80→      }
 81→      if (!hasConfig) {
 82→        setShowSettings(true);
 83→        return;
 84→      }
 85→      loadProjectDirs();
 86→    };
 87→    discover();
 88→  }, [loadProjectDirs]);
 89→
 90→  // Sync session watcher's ongoing status to picker (avoids race condition
 91→  // where picker watcher emits before session watcher updates).
 92→  useEffect(() => {
 93→    if (session.sessionPath) {
 94→      updateSessionOngoing(session.sessionPath, session.ongoing);
 95→    }
 96→  }, [session.sessionPath, session.ongoing, updateSessionOngoing]);
 97→
 98→  // Handle session selection from picker
 99→  const handleSelectSession = useCallback(
100→    (sessionInfo: SessionInfo) => {
101→      loadSession(sessionInfo.path);
102→      setView("list");
103→      setSelectedMessage(0);
104→      clearExpanded();
105→    },
106→    [loadSession, clearExpanded],
107→  );
108→
109→  // Auto-select newest message (last index) when messages load
110→  useEffect(() => {
111→    if (session.messages.length > 0 && view === "list") {
112→      setSelectedMessage((prev) =>
113→        prev >= session.messages.length ? session.messages.length - 1 : prev,
114→      );
115→    }
116→  }, [session.messages.length, view]);
117→
118→  // Open detail view
119→  const openDetail = useCallback((index: number) => {
120→    setSelectedMessage(index);
121→    setView("detail");
122→  }, []);
123→
124→  // -- View actions: each view registers its own expand/collapse handlers --
125→
126→  const viewActionsRef = useViewActionsRef();
127→  const { expandAll, collapseAll } = useViewActionCallbacks(viewActionsRef);
128→
129→  // Register message list expand/collapse when in list view.
130→  const listExpandAll = useCallback(() => {
131→    const claudeIndices: number[] = [];
132→    session.messages.forEach((msg, i) => {
133→      if (msg.role === "claude") claudeIndices.push(i);
134→    });
135→    expandMessages(claudeIndices);
136→  }, [session.messages, expandMessages]);
137→
138→  // Visual top = newest message = last index (display is reversed)
139→  const jumpToTop = useCallback(() => {
140→    setSelectedMessage(Math.max(session.messages.length - 1, 0));
141→  }, [session.messages.length]);
142→
143→  // Visual bottom = oldest message = index 0
144→  const jumpToBottom = useCallback(() => {
145→    setSelectedMessage(0);
146→  }, []);
147→
148→  const openDebug = useCallback(() => {
149→    if (sessionPath) {
150→      loadDebugLog(sessionPath);
151→      setView("debug");
152→    }
153→  }, [sessionPath, loadDebugLog]);
154→
155→  const openTeams = useCallback(() => {
156→    if (session.teams.length > 0) setView("team");
157→  }, [session.teams.length]);
158→
159→  const goToSessions = useCallback(() => {
160→    setView("picker");
161→  }, []);
162→
163→  const backToList = useCallback(() => {
164→    if (sessionPath) setView("list");
165→  }, [sessionPath]);
166→
167→  const toggleKeybinds = useCallback(() => {
168→    setShowKeybinds((v) => !v);
169→  }, []);
170→
171→  const selectProjectByIndex = useCallback(
172→    (index: number) => {
173→      if (index >= 0 && index < projectKeys.length) {
174→        handleSelectProject(projectKeys[index]);
175→      }
176→    },
177→    [projectKeys, handleSelectProject],
178→  );
179→
180→  // Keyboard navigation — build keyMap per view
181→  const keyMap: Record<string, () => void> = {};
182→
183→  // Sidebar-focused shortcuts (override main shortcuts when sidebar has focus)
184→  if (sidebarFocused) {
185→    const sidebarDown = () => setSidebarHighlight((i) => Math.min(i + 1, projectKeys.length - 1));
186→    const sidebarUp = () => setSidebarHighlight((i) => Math.max(i - 1, 0));
187→    keyMap["j"] = sidebarDown;
188→    keyMap["ArrowDown"] = sidebarDown;
189→    keyMap["k"] = sidebarUp;
190→    keyMap["ArrowUp"] = sidebarUp;
191→    keyMap["Enter"] = () => selectProjectByIndex(sidebarHighlight);
192→    keyMap["Escape"] = () => setSidebarFocused(false);
193→    keyMap["l"] = () => setSidebarFocused(false);
194→    keyMap["ArrowRight"] = () => setSidebarFocused(false);
195→    keyMap["?"] = toggleKeybinds;
196→  } else {
197→    switch (view) {
198→      case "list": {
199→        const listDown = () => setSelectedMessage((i) => Math.max(i - 1, 0));
200→        const listUp = () =>
201→          setSelectedMessage((i) => Math.min(i + 1, session.messages.length - 1));
202→        keyMap["j"] = listDown;
203→        keyMap["ArrowDown"] = listDown;
204→        keyMap["k"] = listUp;
205→        keyMap["ArrowUp"] = listUp;
206→        keyMap["G"] = jumpToTop;
207→        keyMap["g"] = jumpToBottom;
208→        keyMap["Tab"] = () => toggleMessage(selectedMessage);
209→        keyMap["Enter"] = () => {
210→          if (session.messages.length > 0) openDetail(selectedMessage);
211→        };
212→        keyMap["e"] = expandAll;
213→        keyMap["c"] = collapseAll;
214→        keyMap["t"] = openTeams;
215→        keyMap["d"] = openDebug;
216→        keyMap["q"] = goToSessions;
217→        keyMap["Escape"] = goToSessions;
218→        keyMap["s"] = goToSessions;
219→        keyMap["?"] = toggleKeybinds;
220→        keyMap["h"] = () => setSidebarFocused(true);
221→        keyMap["ArrowLeft"] = () => setSidebarFocused(true);
222→        break;
223→      }
224→      case "detail":
225→        // j/k/Tab/Enter/q/Escape handled by MessageDetail's own useKeyboard
226→        keyMap["?"] = toggleKeybinds;
227→        break;
228→      case "picker": {
229→        const pickerDown = () =>
230→          setPickerSelectedIndex((i) => Math.min(i + 1, picker.sessions.length - 1));
231→        const pickerUp = () => setPickerSelectedIndex((i) => Math.max(i - 1, 0));
232→        keyMap["j"] = pickerDown;
233→        keyMap["ArrowDown"] = pickerDown;
234→        keyMap["k"] = pickerUp;
235→        keyMap["ArrowUp"] = pickerUp;
236→        keyMap["Enter"] = () => {
237→          if (picker.sessions[pickerSelectedIndex])
238→            handleSelectSession(picker.sessions[pickerSelectedIndex]);
239→        };
240→        keyMap["q"] = backToList;
241→        keyMap["Escape"] = backToList;
242→        keyMap["?"] = toggleKeybinds;
243→        keyMap["h"] = () => setSidebarFocused(true);
244→        keyMap["ArrowLeft"] = () => setSidebarFocused(true);
245→        break;
246→      }
247→      case "team":
248→        keyMap["q"] = () => setView("list");
249→        keyMap["Escape"] = () => setView("list");
250→        keyMap["?"] = toggleKeybinds;
251→        break;
252→      case "debug":
253→        keyMap["q"] = () => setView("list");
254→        keyMap["Escape"] = () => setView("list");
255→        keyMap["?"] = toggleKeybinds;
256→        break;
257→    }
258→  }
259→  useKeyboard(keyMap);
260→
261→  // Keybind bar click actions
262→  const keybindActions: Record<string, () => void> = {};
263→  if (view === "list") {
264→    keybindActions["debug"] = openDebug;
265→    keybindActions["sessions"] = goToSessions;
266→    if (session.teams.length > 0) {
267→      keybindActions["tasks"] = openTeams;
268→    }
269→  } else if (view === "picker") {
270→    keybindActions["back"] = backToList;
271→  } else if (view === "detail") {
272→    keybindActions["back"] = () => setView("list");
273→  } else if (view === "team") {
274→    keybindActions["back"] = () => setView("list");
275→  } else if (view === "debug") {
276→    keybindActions["back"] = () => setView("list");
277→  }
278→
279→  // Render the active view
280→  const renderView = () => {
281→    switch (view) {
282→      case "picker":
283→        return (
284→          <SessionPicker
285→            sessions={picker.sessions}
286→            loading={picker.loading}
287→            searchQuery={picker.searchQuery}
288→            selectedIndex={pickerSelectedIndex}
289→            onSelect={handleSelectSession}
290→            onSearchChange={picker.setSearchQuery}
291→            onSelectIndex={setPickerSelectedIndex}
292→          />
293→        );
294→
295→      case "list":
296→        if (session.loading) {
297→          return (
298→            <div className="session-loading">
299→              <span className="braille-spinner" />
300→              Loading session...
301→            </div>
302→          );
303→        }
304→        return (
305→          <MessageList
306→            messages={session.messages}
307→            selectedIndex={selectedMessage}
308→            expandedSet={expandedMessages}
309→            ongoing={session.ongoing}
310→            onSelect={setSelectedMessage}
311→            onToggle={toggleMessage}
312→            onOpenDetail={openDetail}
313→            viewActionsRef={viewActionsRef}
314→            onExpandAll={listExpandAll}
315→            onCollapseAll={clearExpanded}
316→          />
317→        );
318→
319→      case "detail":
320→        if (session.messages.length > 0 && selectedMessage < session.messages.length) {
321→          return (
322→            <MessageDetail
323→              message={session.messages[selectedMessage]}
324→              ongoing={session.ongoing}
325→              onBack={() => setView("list")}
326→              viewActionsRef={viewActionsRef}
327→            />
328→          );
329→        }
330→        return null;
331→
332→      case "team":
333→        return <TeamBoard teams={session.teams} />;
334→
335→      case "debug":
336→        return <DebugViewer entries={session.debugEntries} viewActionsRef={viewActionsRef} />;
337→    }
338→  };
339→
340→  return (
341→    <div className="app">
342→      {/* Info bar — only show when we have a loaded session */}
343→      {session.sessionPath && view !== "picker" && (
344→        <InfoBar
345→          meta={session.meta}
346→          gitInfo={session.gitInfo}
347→          messages={session.messages}
348→          sessionTotals={session.sessionTotals}
349→          sessionPath={session.sessionPath}
350→          ongoing={session.ongoing}
351→        />
352→      )}
353→
354→      {/* View toolbar */}
355→      <ViewToolbar
356→        view={view}
357→        hasTeams={session.teams.length > 0}
358→        hasSession={!!session.sessionPath}
359→        onGoToSessions={goToSessions}
360→        onExpandAll={expandAll}
361→        onCollapseAll={collapseAll}
362→        onOpenTeams={openTeams}
363→        onOpenDebug={openDebug}
364→        onBackToList={backToList}
365→        onOpenSettings={() => setShowSettings(true)}
366→      />
367→
368→      <div className="app-body">
369→        <ProjectTree
370→          sessions={picker.allSessions}
371→          selectedProject={selectedProject}
372→          highlightedIndex={sidebarHighlight}
373→          isFocused={sidebarFocused}
374→          onSelectProject={handleSelectProject}
375→          onRefresh={loadProjectDirs}
376→          onFocus={() => setSidebarFocused(true)}
377→          refreshing={picker.loading}
378→          style={{ width: sidebarWidth, minWidth: 100, maxWidth: 400 }}
379→        />
380→        <ResizeHandle onResize={setSidebarWidth} />
381→        <div className="main-content" onClick={() => setSidebarFocused(false)}>
382→          {renderView()}
383→        </div>
