409→/* ─── PanelColumn: renders ResizeHandle + either list or detail ─── */
410→
411→interface PanelColumnProps {
412→  entry: PanelEntry;
413→  depth: number;
414→  style?: React.CSSProperties;
415→  isFocused: boolean;
416→  panelStack: PanelEntry[];
417→  onOpenDetail: (msg: DisplayMessage) => void;
418→  onBackToList: () => void;
419→  onOpenSubagent: (item: DisplayItem) => void;
420→  onClose: () => void;
421→  onResize: (width: number) => void;
422→  onFocus: () => void;
423→  onRegisterNav: (nav: ColumnNav | null) => void;
424→}
425→
426→function PanelColumn({
427→  entry,
428→  depth,
429→  style,
430→  isFocused,
431→  panelStack,
432→  onOpenDetail,
433→  onBackToList,
434→  onOpenSubagent,
435→  onClose,
436→  onResize,
437→  onFocus,
438→  onRegisterNav,
439→}: PanelColumnProps) {
440→  return (
441→    <>
442→      <ResizeHandle onResize={onResize} />
443→      {entry.kind === "agent-list" ? (
444→        <AgentListColumn
445→          item={entry.item}
446→          style={style}
447→          isFocused={isFocused}
448→          onOpenDetail={onOpenDetail}
449→          onClose={onClose}
450→          onFocus={onFocus}
451→          onRegisterNav={onRegisterNav}
452→        />
453→      ) : (
454→        <AgentDetailColumn
455→          item={entry.item}
456→          msg={entry.msg}
457→          style={style}
458→          isFocused={isFocused}
459→          depth={depth}
460→          panelStack={panelStack}
461→          onOpenSubagent={onOpenSubagent}
462→          onBack={onBackToList}
463→          onClose={onClose}
464→          onFocus={onFocus}
465→          onRegisterNav={onRegisterNav}
466→        />
467→      )}
468→    </>
469→  );
470→}
471→
472→/* ─── AgentListColumn: shows agent header + message list ─── */
473→
474→interface AgentListColumnProps {
475→  item: DisplayItem;
476→  style?: React.CSSProperties;
477→  isFocused: boolean;
478→  onOpenDetail: (msg: DisplayMessage) => void;
479→  onClose: () => void;
480→  onFocus: () => void;
481→  onRegisterNav: (nav: ColumnNav | null) => void;
482→}
483→
484→function AgentListColumn({
485→  item,
486→  style,
487→  isFocused,
488→  onOpenDetail,
489→  onClose,
490→  onFocus,
491→  onRegisterNav,
492→}: AgentListColumnProps) {
493→  const messages = item.subagent_messages;
494→  const [selectedMsg, setSelectedMsg] = useState(messages.length - 1);
495→  const {
496→    set: expandedSet,
497→    toggle: toggleMsg,
498→    addAll: expandAllMsgs,
499→    clear: clearMsgs,
500→  } = useToggleSet();
501→  const listRef = useAutoScroll<HTMLDivElement>(messages.length);
502→  const selectedRef = useScrollToSelected(selectedMsg);
503→  const panelColor = item.team_color ? getTeamColor(item.team_color) : undefined;
504→
505→  const handleClick = useCallback(
506→    (index: number) => {
507→      onFocus();
508→      if (selectedMsg === index) {
509→        toggleMsg(index);
510→      } else {
511→        setSelectedMsg(index);
512→      }
513→    },
514→    [selectedMsg, toggleMsg, onFocus],
515→  );
516→
517→  // Expose navigation to parent via callback ref
518→  const navRef = useRef<ColumnNav>({
519→    moveUp: () => setSelectedMsg((i) => Math.max(i - 1, 0)),
520→    moveDown: () => setSelectedMsg((i) => Math.min(i + 1, messages.length - 1)),
521→    toggle: () => toggleMsg(selectedMsg),
522→    enter: () => {
523→      if (messages[selectedMsg]) onOpenDetail(messages[selectedMsg]);
524→    },
525→    itemCount: () => messages.length,
526→    expandAll: () => expandAllMsgs(messages.map((_, i) => i)),
527→    collapseAll: () => clearMsgs(),
528→  });
529→  navRef.current.moveUp = () => setSelectedMsg((i) => Math.max(i - 1, 0));
530→  navRef.current.moveDown = () => setSelectedMsg((i) => Math.min(i + 1, messages.length - 1));
531→  navRef.current.toggle = () => toggleMsg(selectedMsg);
532→  navRef.current.enter = () => {
533→    if (messages[selectedMsg]) onOpenDetail(messages[selectedMsg]);
534→  };
535→  navRef.current.itemCount = () => messages.length;
536→  navRef.current.expandAll = () => expandAllMsgs(messages.map((_, i) => i));
537→  navRef.current.collapseAll = () => clearMsgs();
538→
539→  // Register/unregister nav on mount/unmount
540→  useLayoutEffect(() => {
541→    onRegisterNav(navRef.current);
542→    return () => onRegisterNav(null);
543→  }, [onRegisterNav]);
544→
545→  const ordered = useMemo(() => {
546→    const indices: number[] = [];
547→    for (let i = 0; i < messages.length; i++) indices.push(i);
548→    return indices;
549→  }, [messages.length]);
550→
551→  return (
552→    <div
553→      className={`agent-panel${isFocused ? " agent-panel--focused" : ""}`}
554→      style={
555→        {
556→          ...(panelColor ? { background: `${panelColor}08` } : {}),
557→          ...style,
558→        } as React.CSSProperties
559→      }
560→      onClick={onFocus}
561→    >
562→      <AgentPanelHeader item={item} panelColor={panelColor} onClose={onClose} />
563→      <div className="agent-panel__content">
564→        <div className="agent-panel__list" ref={listRef}>
565→          {ordered.map((i) => {
566→            const msg = messages[i];
567→            if (msg.role === "compact") {
568→              return (
569→                <div key={i} className="compact-separator">
570→                  <div className="compact-separator__line">
571→                    <span className="compact-separator__rule" />
572→                    <span>{msg.content}</span>
573→                    <span className="compact-separator__rule" />
574→                  </div>
575→                </div>
576→              );
577→            }
578→            const isSelected = i === selectedMsg;
579→            const isExpanded = expandedSet.has(i);
580→            const isLast = i === messages.length - 1;
581→            return (
582→              <MessageItem
583→                key={i}
584→                ref={isSelected ? selectedRef : undefined}
585→                message={msg}
586→                index={i}
587→                isSelected={isSelected}
588→                isExpanded={isExpanded}
589→                isOngoing={isLast && item.subagent_ongoing}
590→                onClick={handleClick}
591→                onOpenDetail={(idx) => onOpenDetail(messages[idx])}
592→              />
593→            );
594→          })}
595→        </div>
596→      </div>
597→    </div>
