761→/* ─── Shared agent panel header ─── */
762→
763→function AgentPanelHeader({
764→  item,
765→  panelColor,
766→  onClose,
767→}: {
768→  item: DisplayItem;
769→  panelColor?: string;
770→  onClose: () => void;
771→}) {
772→  return (
773→    <div
774→      className="agent-panel__header"
775→      style={panelColor ? { background: `${panelColor}10` } : undefined}
776→    >
777→      <button className="agent-panel__close" onClick={onClose}>
778→        <IoMdCloseCircle className="icon--close" />
779→      </button>
780→      <span className="agent-panel__icon">
781→        <ClaudeIcon />
782→      </span>
783→      <span className="agent-panel__type" style={panelColor ? { color: panelColor } : undefined}>
784→        {item.subagent_type || item.tool_name || "Subagent"}
785→      </span>
786→      {(item.subagent_desc || item.tool_summary) && (
787→        <span className="agent-panel__desc">{item.subagent_desc || item.tool_summary}</span>
788→      )}
