  1→import type { ViewState } from "../types";
  2→
  3→interface KeybindBarProps {
  4→  view: ViewState;
  5→  hasTeams: boolean;
  6→  showHints?: boolean;
  7→  onToggle?: () => void;
  8→  actions?: Record<string, () => void>;
  9→}
 10→
 11→interface KeyHint {
 12→  key: string;
 13→  label: string;
 14→}
 15→
 16→const listKeys: KeyHint[] = [
 17→  { key: "j/k", label: "nav" },
 18→  { key: "\u2191/\u2193", label: "scroll" },
 19→  { key: "G/g", label: "jump" },
 20→  { key: "Tab", label: "toggle" },
 21→  { key: "Enter", label: "detail" },
 22→  { key: "d", label: "debug" },
 23→  { key: "e/c", label: "expand/collapse" },
 24→  { key: "q", label: "sessions" },
 25→];
 26→
 27→const listKeysWithTeams: KeyHint[] = [
 28→  ...listKeys.slice(0, 6),
 29→  { key: "t", label: "tasks" },
 30→  ...listKeys.slice(6),
 31→];
 32→
 33→const detailKeys: KeyHint[] = [
 34→  { key: "j/k", label: "items" },
 35→  { key: "Tab", label: "toggle" },
 36→  { key: "Enter", label: "open" },
 37→  { key: "h/l", label: "panels" },
 38→  { key: "q/Esc", label: "back" },
 39→];
 40→
 41→const pickerKeys: KeyHint[] = [
 42→  { key: "j/k", label: "nav" },
 43→  { key: "Enter", label: "open" },
 44→  { key: "/", label: "search" },
 45→  { key: "q/Esc", label: "back" },
 46→];
 47→
 48→const debugKeys: KeyHint[] = [{ key: "q/Esc", label: "back" }];
 49→
 50→const teamKeys: KeyHint[] = [{ key: "q/Esc", label: "back" }];
 51→
 52→function getKeys(view: ViewState, hasTeams: boolean): KeyHint[] {
 53→  switch (view) {
 54→    case "list":
 55→      return hasTeams ? listKeysWithTeams : listKeys;
 56→    case "detail":
 57→      return detailKeys;
 58→    case "picker":
 59→      return pickerKeys;
 60→    case "debug":
 61→      return debugKeys;
 62→    case "team":
 63→      return teamKeys;
 64→  }
 65→}
 66→
 67→export function KeybindBar({
 68→  view,
 69→  hasTeams,
 70→  showHints = true,
 71→  onToggle,
 72→  actions,
 73→}: KeybindBarProps) {
 74→  const keys = getKeys(view, hasTeams);
 75→
 76→  return (
